1	export type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { op: "quote"; items: Item[] };
8	
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	
18	export type ScenarioResult = {
19	  results: QuoteResult[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const BLOCK_SIZE = 3;
34	const BLOCK_PRICE = 60;
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const LOYALTY_YEARS_THRESHOLD = 2;
38	const LOYALTY_DISCOUNT_RATE = 0.2;
39	const FIRST_INSURANCE_RATE = 0.1;
40	
41	const CURSE_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const FOLLOWUP_DISCOUNT_RATE = 0.15;
45	
46	const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;
47	
48	const countsByType = (items: Item[]): Map<string, number> =>
49	  items.reduce(
50	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
51	    new Map<string, number>()
52	  );
53	
54	const groupTotal = (type: string, count: number): number =>
55	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
56	    ? BLOCK_PRICE
57	    : count * unitPrice(type);
58	
59	const sumBasePremiums = (items: Item[]): number =>
60	  Array.from(countsByType(items)).reduce(
61	    (total, [type, count]) => total + groupTotal(type, count),
62	    0
63	  );
64	
65	const itemSurcharges = (item: Item): number => {
66	  const base = unitPrice(item.type);
67	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
68	  const enchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
69	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
70	    : 0;
71	  return curse + enchantment;
72	};
73	
74	const sumItemSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
76	
77	const loyaltyDiscount = (
78	  basePremiums: number,
79	  customer: { yearsWithMHPCO: number }
80	): number =>
81	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
82	    ? basePremiums * LOYALTY_DISCOUNT_RATE
83	    : 0;
84	
85	const quote = (
86	  { items }: QuoteStep,
87	  customer: { yearsWithMHPCO: number },
88	  quoteIndex: number
89	): QuoteResult => {
90	  const basePremiums = sumBasePremiums(items);
91	  const followupDiscount = quoteIndex > 0 ? basePremiums * FOLLOWUP_DISCOUNT_RATE : 0;
92	  const raw =
93	    basePremiums +
94	    sumItemSurcharges(items) -
95	    loyaltyDiscount(basePremiums, customer) +
96	    basePremiums * FIRST_INSURANCE_RATE -
97	    followupDiscount +
98	    PROCESSING_FEE;
99	  return { premium: Math.ceil(raw) };
100	};
101	
102	export const runScenario = (scenario: Scenario): ScenarioResult => ({
103	  results: scenario.steps.map((step, index) => quote(step, scenario.customer, index)),
104	});
